scope:
  categories_whitelist:
    - movilidad
    - medio-ambiente-y-cambio-climatico
    - desarrollo-urbano-vivienda-y-territorio
    - inclusion-y-bienestar-social
    - justicia-y-seguridad
    - atencion-ciudadana
    - salud
